import { describe, expect, it } from 'vitest'
import {
  type FloorGpsBoundsColumns,
  type FloorGpsBoundsStore,
  type FloorGpsBoundsStoreTx,
  FloorGpsBoundsError,
  parseFloorGpsBoundsUpdatePayload,
  serializeFloorGpsBounds,
  toNavFloorGpsBounds,
  updateFloorGpsBoundsFromPayload,
} from './floorGpsBounds'

interface InMemoryFloorRow extends FloorGpsBoundsColumns {
  id: number
}

interface InMemoryFloorStore {
  store: FloorGpsBoundsStore
  getFloor(floorId: number): InMemoryFloorRow | null
  snapshotFloors(): InMemoryFloorRow[]
}

function cloneFloorRow(row: InMemoryFloorRow): InMemoryFloorRow {
  return { ...row }
}

function createInMemoryFloorStore(rows: InMemoryFloorRow[]): InMemoryFloorStore {
  let committedRows = new Map(rows.map((row) => [row.id, cloneFloorRow(row)]))

  const buildTx = (workingRows: Map<number, InMemoryFloorRow>): FloorGpsBoundsStoreTx => ({
    async getFloorById(floorId) {
      const row = workingRows.get(floorId)
      return row ? cloneFloorRow(row) : null
    },

    async updateFloorGpsBounds(floorId, bounds) {
      const current = workingRows.get(floorId)
      if (!current) {
        return null
      }

      const next = { ...current, ...bounds }
      workingRows.set(floorId, next)
      return cloneFloorRow(next)
    },
  })

  return {
    store: {
      async transaction(callback) {
        const workingRows = new Map(
          Array.from(committedRows.entries()).map(([id, row]) => [id, cloneFloorRow(row)]),
        )

        const result = await callback(buildTx(workingRows))
        committedRows = workingRows
        return result
      },
    },

    getFloor(floorId) {
      const row = committedRows.get(floorId)
      return row ? cloneFloorRow(row) : null
    },

    snapshotFloors() {
      return Array.from(committedRows.values())
        .map((row) => cloneFloorRow(row))
        .sort((left, right) => left.id - right.id)
    },
  }
}

describe('serializeFloorGpsBounds', () => {
  it('serializes gpsBounds only when complete tuple is present', () => {
    expect(
      serializeFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: 14.5822,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toEqual({
      gpsBounds: {
        minLat: 14.5811,
        maxLat: 14.5822,
        minLng: 121.0412,
        maxLng: 121.0423,
      },
    })

    expect(
      serializeFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: 14.5822,
        gpsMinLng: null,
        gpsMaxLng: 121.0423,
      }),
    ).toEqual({})

    expect(
      serializeFloorGpsBounds({
        gpsMinLat: null,
        gpsMaxLat: null,
        gpsMinLng: null,
        gpsMaxLng: null,
      }),
    ).toEqual({})
  })
})

describe('toNavFloorGpsBounds', () => {
  it('returns null when one or more tuple values are missing', () => {
    expect(
      toNavFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: null,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toBeNull()
  })

  it('returns null when tuple contains non-finite values', () => {
    expect(
      toNavFloorGpsBounds({
        gpsMinLat: Number.NaN,
        gpsMaxLat: 14.5822,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toBeNull()
  })
})

describe('parseFloorGpsBoundsUpdatePayload', () => {
  it('parses complete numeric tuples', () => {
    expect(
      parseFloorGpsBoundsUpdatePayload({
        minLat: 14.5811,
        maxLat: 14.5822,
        minLng: 121.0412,
        maxLng: 121.0423,
      }),
    ).toEqual({
      gpsMinLat: 14.5811,
      gpsMaxLat: 14.5822,
      gpsMinLng: 121.0412,
      gpsMaxLng: 121.0423,
    })
  })

  it('rejects non-object payloads as INVALID_REQUEST', () => {
    expect(() => parseFloorGpsBoundsUpdatePayload('invalid')).toThrowError(FloorGpsBoundsError)

    try {
      parseFloorGpsBoundsUpdatePayload('invalid')
      throw new Error('Expected INVALID_REQUEST error')
    } catch (error) {
      expect(error).toMatchObject<Partial<FloorGpsBoundsError>>({
        code: 'INVALID_REQUEST',
        status: 400,
      })
    }
  })
})

describe('updateFloorGpsBoundsFromPayload', () => {
  it('updates and returns authoritative gpsBounds when complete tuple is provided', async () => {
    const memory = createInMemoryFloorStore([
      {
        id: 101,
        gpsMinLat: null,
        gpsMaxLat: null,
        gpsMinLng: null,
        gpsMaxLng: null,
      },
    ])

    const result = await updateFloorGpsBoundsFromPayload(
      101,
      {
        minLat: 14.5811,
        maxLat: 14.5822,
        minLng: 121.0412,
        maxLng: 121.0423,
      },
      { store: memory.store },
    )

    expect(result).toEqual({
      ok: true,
      floorId: 101,
      gpsBounds: {
        minLat: 14.5811,
        maxLat: 14.5822,
        minLng: 121.0412,
        maxLng: 121.0423,
      },
    })

    expect(memory.getFloor(101)).toEqual({
      id: 101,
      gpsMinLat: 14.5811,
      gpsMaxLat: 14.5822,
      gpsMinLng: 121.0412,
      gpsMaxLng: 121.0423,
    })
  })

  it('clears gps bounds when full null tuple is provided', async () => {
    const memory = createInMemoryFloorStore([
      {
        id: 102,
        gpsMinLat: 14.5811,
        gpsMaxLat: 14.5822,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      },
    ])

    const result = await updateFloorGpsBoundsFromPayload(
      102,
      {
        minLat: null,
        maxLat: null,
        minLng: null,
        maxLng: null,
      },
      { store: memory.store },
    )

    expect(result).toEqual({
      ok: true,
      floorId: 102,
      gpsBounds: null,
    })

    expect(memory.getFloor(102)).toEqual({
      id: 102,
      gpsMinLat: null,
      gpsMaxLat: null,
      gpsMinLng: null,
      gpsMaxLng: null,
    })
  })

  it('returns GPS_BOUNDS_INCOMPLETE when tuple is partially provided', async () => {
    const memory = createInMemoryFloorStore([
      {
        id: 201,
        gpsMinLat: 14.57,
        gpsMaxLat: 14.58,
        gpsMinLng: 121.04,
        gpsMaxLng: 121.05,
      },
    ])

    const before = memory.snapshotFloors()

    await expect(
      updateFloorGpsBoundsFromPayload(
        201,
        {
          minLat: 14.571,
          maxLat: 14.582,
          minLng: null,
          maxLng: 121.052,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<FloorGpsBoundsError>>({
      code: 'GPS_BOUNDS_INCOMPLETE',
      status: 400,
    })

    expect(memory.snapshotFloors()).toEqual(before)
  })

  it('returns BOUNDS_RANGE_INVALID when min/max ordering is invalid', async () => {
    const memory = createInMemoryFloorStore([
      {
        id: 202,
        gpsMinLat: 14.57,
        gpsMaxLat: 14.58,
        gpsMinLng: 121.04,
        gpsMaxLng: 121.05,
      },
    ])

    const before = memory.snapshotFloors()

    await expect(
      updateFloorGpsBoundsFromPayload(
        202,
        {
          minLat: 14.59,
          maxLat: 14.58,
          minLng: 121.04,
          maxLng: 121.05,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<FloorGpsBoundsError>>({
      code: 'BOUNDS_RANGE_INVALID',
      status: 400,
    })

    expect(memory.snapshotFloors()).toEqual(before)
  })

  it('returns FLOOR_NOT_FOUND when floor id does not exist', async () => {
    const memory = createInMemoryFloorStore([])

    await expect(
      updateFloorGpsBoundsFromPayload(
        999,
        {
          minLat: 14.5811,
          maxLat: 14.5822,
          minLng: 121.0412,
          maxLng: 121.0423,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<FloorGpsBoundsError>>({
      code: 'FLOOR_NOT_FOUND',
      status: 404,
    })
  })
})

import type { NavFloor } from '@shared/types'
import { renderToStaticMarkup } from 'react-dom/server'
import { describe, expect, it } from 'vitest'
import ManageFloorsModal, { deriveGpsBoundsRowUiState } from './ManageFloorsModal'

function makeFloor(overrides: Partial<NavFloor> & { id: number; floorNumber: number }): NavFloor {
  return {
    id: overrides.id,
    floorNumber: overrides.floorNumber,
    imagePath: overrides.imagePath ?? `floor-plan-1-${overrides.floorNumber}.png`,
    updatedAt: overrides.updatedAt ?? '2026-03-24T00:00:00.000Z',
    gpsBounds: overrides.gpsBounds,
    nodes: overrides.nodes ?? [],
    edges: overrides.edges ?? [],
  }
}

const noop = () => {}

describe('ManageFloorsModal GPS helpers', () => {
  it('renders inline validation error and blocks save for partial gps tuple', () => {
    const rowUiState = deriveGpsBoundsRowUiState(
      {
        minLat: '14.552',
        maxLat: '',
        minLng: '121.012',
        maxLng: '121.016',
      },
      null,
      { isPending: false, isSaving: false },
    )

    expect(rowUiState.validationError).toContain('GPS_BOUNDS_INCOMPLETE')
    expect(rowUiState.requestPayload).toBeNull()
    expect(rowUiState.isSaveDisabled).toBe(true)
  })

  it('disables save while pending even when tuple is valid', () => {
    const rowUiState = deriveGpsBoundsRowUiState(
      {
        minLat: '14.552',
        maxLat: '14.553',
        minLng: '121.012',
        maxLng: '121.016',
      },
      null,
      { isPending: true, isSaving: false },
    )

    expect(rowUiState.validationError).toBeNull()
    expect(rowUiState.requestPayload).toEqual({
      minLat: 14.552,
      maxLat: 14.553,
      minLng: 121.012,
      maxLng: 121.016,
    })
    expect(rowUiState.isSaveDisabled).toBe(true)
  })
})

describe('ManageFloorsModal GPS rendering', () => {
  it('shows campus floor gps controls and hides add/replace/delete floor controls in campus mode', () => {
    const html = renderToStaticMarkup(
      <ManageFloorsModal
        isOpen
        buildingId={99}
        floors={[makeFloor({ id: 900, floorNumber: 0 })]}
        isCampusMode
        onClose={noop}
        onFloorAdded={noop}
        onFloorDeleted={noop}
        onFloorImageReplaced={noop}
        onFloorGpsBoundsSaved={noop}
      />,
    )

    expect(html).toContain('Campus Map')
    expect(html).toContain('Save GPS Bounds')
    expect(html).not.toContain('Add Floor')
    expect(html).not.toContain('Replace Image')
    expect(html).not.toContain('Delete')
  })

  it('keeps add floor controls available in building mode', () => {
    const html = renderToStaticMarkup(
      <ManageFloorsModal
        isOpen
        buildingId={1}
        floors={[
          makeFloor({
            id: 100,
            floorNumber: 1,
            gpsBounds: {
              minLat: 14.551,
              maxLat: 14.552,
              minLng: 121.01,
              maxLng: 121.011,
            },
          }),
        ]}
        onClose={noop}
        onFloorAdded={noop}
        onFloorDeleted={noop}
        onFloorImageReplaced={noop}
        onFloorGpsBoundsSaved={noop}
      />,
    )

    expect(html).toContain('Floor 1')
    expect(html).toContain('Add Floor')
    expect(html).toContain('Replace Image')
    expect(html).toContain('Delete')
  })
})

import { describe, expect, it } from 'vitest'
import {
  buildGpsBoundsRequestPayload,
  createGpsBoundsDraft,
  createGpsBoundsDraftMap,
  deriveGpsBoundsFormState,
} from './gpsBoundsForm'

describe('gpsBoundsForm', () => {
  it('builds draft strings from persisted gps bounds', () => {
    expect(
      createGpsBoundsDraft({
        minLat: 14.554,
        maxLat: 14.555,
        minLng: 121.02,
        maxLng: 121.021,
      }),
    ).toEqual({
      minLat: '14.554',
      maxLat: '14.555',
      minLng: '121.02',
      maxLng: '121.021',
    })

    expect(createGpsBoundsDraft(null)).toEqual({
      minLat: '',
      maxLat: '',
      minLng: '',
      maxLng: '',
    })
  })

  it('creates floor-id keyed draft map from floor metadata', () => {
    const drafts = createGpsBoundsDraftMap([
      {
        id: 10,
        gpsBounds: {
          minLat: 1,
          maxLat: 2,
          minLng: 3,
          maxLng: 4,
        },
      },
      {
        id: 11,
      },
    ])

    expect(drafts).toEqual({
      10: {
        minLat: '1',
        maxLat: '2',
        minLng: '3',
        maxLng: '4',
      },
      11: {
        minLat: '',
        maxLat: '',
        minLng: '',
        maxLng: '',
      },
    })
  })

  it('returns clear payload as valid when all fields are empty', () => {
    const formState = deriveGpsBoundsFormState(
      {
        minLat: '',
        maxLat: '',
        minLng: '',
        maxLng: '',
      },
      null,
    )

    expect(formState.isValid).toBe(true)
    expect(formState.errorCode).toBeNull()
    expect(formState.payload).toEqual({
      minLat: null,
      maxLat: null,
      minLng: null,
      maxLng: null,
    })
    expect(formState.hasChanges).toBe(false)
  })

  it('returns GPS_BOUNDS_INCOMPLETE when tuple is partially provided', () => {
    const formState = deriveGpsBoundsFormState({
      minLat: '14.55',
      maxLat: '',
      minLng: '121.0',
      maxLng: '121.1',
    })

    expect(formState.isValid).toBe(false)
    expect(formState.errorCode).toBe('GPS_BOUNDS_INCOMPLETE')
    expect(formState.error).toContain('GPS_BOUNDS_INCOMPLETE')
    expect(formState.payload).toBeNull()
  })

  it('returns BOUNDS_RANGE_INVALID when min/max ordering is invalid', () => {
    const formState = deriveGpsBoundsFormState({
      minLat: '14.56',
      maxLat: '14.56',
      minLng: '121.10',
      maxLng: '121.09',
    })

    expect(formState.isValid).toBe(false)
    expect(formState.errorCode).toBe('BOUNDS_RANGE_INVALID')
    expect(formState.error).toContain('minLat must be < maxLat')
    expect(formState.payload).toBeNull()
  })

  it('returns valid numeric payload and unchanged=false when tuple differs from persisted bounds', () => {
    const formState = deriveGpsBoundsFormState(
      {
        minLat: ' 14.5501 ',
        maxLat: '14.5502',
        minLng: '121.0201',
        maxLng: '121.0202',
      },
      {
        minLat: 14.55,
        maxLat: 14.56,
        minLng: 121.02,
        maxLng: 121.03,
      },
    )

    expect(formState.isValid).toBe(true)
    expect(formState.error).toBeNull()
    expect(formState.payload).toEqual({
      minLat: 14.5501,
      maxLat: 14.5502,
      minLng: 121.0201,
      maxLng: 121.0202,
    })
    expect(formState.nextGpsBounds).toEqual({
      minLat: 14.5501,
      maxLat: 14.5502,
      minLng: 121.0201,
      maxLng: 121.0202,
    })
    expect(formState.hasChanges).toBe(true)
  })

  it('buildGpsBoundsRequestPayload returns null for invalid drafts and tuples for clear/set states', () => {
    expect(
      buildGpsBoundsRequestPayload({
        minLat: '1',
        maxLat: '',
        minLng: '2',
        maxLng: '3',
      }),
    ).toBeNull()

    expect(
      buildGpsBoundsRequestPayload({
        minLat: '',
        maxLat: '',
        minLng: '',
        maxLng: '',
      }),
    ).toEqual({
      minLat: null,
      maxLat: null,
      minLng: null,
      maxLng: null,
    })

    expect(
      buildGpsBoundsRequestPayload({
        minLat: '1',
        maxLat: '2',
        minLng: '3',
        maxLng: '4',
      }),
    ).toEqual({
      minLat: 1,
      maxLat: 2,
      minLng: 3,
      maxLng: 4,
    })
  })
})

import type { NavFloorGpsBounds } from '@shared/types'
import { eq } from 'drizzle-orm'
import { db } from './db/client'
import { floors } from './db/schema'

export interface FloorGpsBoundsColumns {
  gpsMinLat: number | null
  gpsMaxLat: number | null
  gpsMinLng: number | null
  gpsMaxLng: number | null
}

export type FloorGpsBoundsErrorCode =
  | 'INVALID_REQUEST'
  | 'GPS_BOUNDS_INCOMPLETE'
  | 'BOUNDS_RANGE_INVALID'
  | 'FLOOR_NOT_FOUND'

type FloorGpsBoundsErrorStatus = 400 | 404

const FLOOR_GPS_BOUNDS_ERROR_STATUS = {
  INVALID_REQUEST: 400,
  GPS_BOUNDS_INCOMPLETE: 400,
  BOUNDS_RANGE_INVALID: 400,
  FLOOR_NOT_FOUND: 404,
} as const satisfies Record<FloorGpsBoundsErrorCode, FloorGpsBoundsErrorStatus>

export class FloorGpsBoundsError extends Error {
  readonly code: FloorGpsBoundsErrorCode
  readonly status: FloorGpsBoundsErrorStatus

  constructor(code: FloorGpsBoundsErrorCode, message: string) {
    super(message)
    this.name = 'FloorGpsBoundsError'
    this.code = code
    this.status = FLOOR_GPS_BOUNDS_ERROR_STATUS[code]
  }
}

export interface FloorGpsBoundsUpdateResult {
  ok: true
  floorId: number
  gpsBounds: NavFloorGpsBounds | null
}

interface FloorGpsBoundsRow extends FloorGpsBoundsColumns {
  id: number
}

export interface FloorGpsBoundsStoreTx {
  getFloorById(floorId: number): Promise<FloorGpsBoundsRow | null>
  updateFloorGpsBounds(floorId: number, bounds: FloorGpsBoundsColumns): Promise<FloorGpsBoundsRow | null>
}

export interface FloorGpsBoundsStore {
  transaction<T>(callback: (tx: FloorGpsBoundsStoreTx) => Promise<T>): Promise<T>
}

type DrizzleFloorGpsBoundsTx = Pick<typeof db, 'select' | 'update'>

function isFiniteNumber(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value)
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

function parseFloorGpsBoundsTuple(values: {
  minLat: unknown
  maxLat: unknown
  minLng: unknown
  maxLng: unknown
}): FloorGpsBoundsColumns {
  const { minLat, maxLat, minLng, maxLng } = values
  const tupleValues = [minLat, maxLat, minLng, maxLng] as const

  if (tupleValues.some(value => value === undefined)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'minLat, maxLat, minLng, and maxLng must all be provided',
    )
  }

  if (tupleValues.every(value => value === null)) {
    return {
      gpsMinLat: null,
      gpsMaxLat: null,
      gpsMinLng: null,
      gpsMaxLng: null,
    }
  }

  if (tupleValues.some(value => value === null)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'GPS bounds must be a complete numeric tuple or a full null clear tuple',
    )
  }

  if (
    !isFiniteNumber(minLat)
    || !isFiniteNumber(maxLat)
    || !isFiniteNumber(minLng)
    || !isFiniteNumber(maxLng)
  ) {
    throw new FloorGpsBoundsError(
      'INVALID_REQUEST',
      'minLat, maxLat, minLng, and maxLng must be finite numbers or all null',
    )
  }

  if (minLat >= maxLat || minLng >= maxLng) {
    throw new FloorGpsBoundsError(
      'BOUNDS_RANGE_INVALID',
      'GPS bounds must satisfy minLat < maxLat and minLng < maxLng',
    )
  }

  return {
    gpsMinLat: minLat,
    gpsMaxLat: maxLat,
    gpsMinLng: minLng,
    gpsMaxLng: maxLng,
  }
}

/**
 * Converts nullable DB floor GPS columns into a complete GPS bounds object.
 * Returns null when any value is missing (or non-finite), ensuring callers never
 * serialize partial coordinate tuples.
 */
export function toNavFloorGpsBounds(row: FloorGpsBoundsColumns): NavFloorGpsBounds | null {
  if (
    !isFiniteNumber(row.gpsMinLat)
    || !isFiniteNumber(row.gpsMaxLat)
    || !isFiniteNumber(row.gpsMinLng)
    || !isFiniteNumber(row.gpsMaxLng)
  ) {
    return null
  }

  return {
    minLat: row.gpsMinLat,
    maxLat: row.gpsMaxLat,
    minLng: row.gpsMinLng,
    maxLng: row.gpsMaxLng,
  }
}

export function serializeFloorGpsBounds(row: FloorGpsBoundsColumns): { gpsBounds?: NavFloorGpsBounds } {
  const gpsBounds = toNavFloorGpsBounds(row)
  return gpsBounds ? { gpsBounds } : {}
}

export function parseFloorGpsBoundsUpdatePayload(payload: unknown): FloorGpsBoundsColumns {
  if (!isRecord(payload)) {
    throw new FloorGpsBoundsError('INVALID_REQUEST', 'Request body must be a JSON object')
  }

  return parseFloorGpsBoundsTuple({
    minLat: payload.minLat,
    maxLat: payload.maxLat,
    minLng: payload.minLng,
    maxLng: payload.maxLng,
  })
}

function createDrizzleStoreTx(tx: DrizzleFloorGpsBoundsTx): FloorGpsBoundsStoreTx {
  return {
    async getFloorById(floorId) {
      const [row] = await tx
        .select({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })
        .from(floors)
        .where(eq(floors.id, floorId))
        .limit(1)

      return row ?? null
    },

    async updateFloorGpsBounds(floorId, bounds) {
      const [row] = await tx
        .update(floors)
        .set({
          ...bounds,
          updatedAt: new Date().toISOString(),
        })
        .where(eq(floors.id, floorId))
        .returning({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })

      return row ?? null
    },
  }
}

const drizzleFloorGpsBoundsStore: FloorGpsBoundsStore = {
  transaction(callback) {
    return db.transaction(async (tx) => callback(createDrizzleStoreTx(tx)))
  },
}

async function executeUpdateFloorGpsBounds(
  tx: FloorGpsBoundsStoreTx,
  floorId: number,
  bounds: FloorGpsBoundsColumns,
): Promise<FloorGpsBoundsUpdateResult> {
  const existingFloor = await tx.getFloorById(floorId)
  if (!existingFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  const updatedFloor = await tx.updateFloorGpsBounds(existingFloor.id, bounds)
  if (!updatedFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  return {
    ok: true,
    floorId: updatedFloor.id,
    gpsBounds: toNavFloorGpsBounds(updatedFloor),
  }
}

export async function updateFloorGpsBounds(
  floorId: number,
  bounds: FloorGpsBoundsColumns,
  options?: { store?: FloorGpsBoundsStore },
): Promise<FloorGpsBoundsUpdateResult> {
  if (!Number.isInteger(floorId) || floorId <= 0) {
